                            {isLoading ? <Loader2 className="animate-spin w-6 h-6"/> : isPlaying ? <Volume2 className="w-6 h-6 animate-pulse"/> : <Play className="w-6 h-6 fill-current"/>}
                        </button>
                    </div>
