// 🆕 Componente de Filtro de Data Reutilizável
const DateRangeFilter = ({ startDate, setStartDate, endDate, setEndDate }: { startDate: string, setStartDate: (v: string) => void, endDate: string, setEndDate: (v: string) => void }) => (
    <div className="flex gap-2 items-center flex-1 min-w-[200px]">
        <div className="relative flex-1">
            <span className="absolute -top-2 left-2 bg-white px-1 text-[10px] font-bold text-slate-400 pointer-events-none">De</span>
            <input 
                type="date" 
                value={startDate} 
                onChange={e => setStartDate(e.target.value)} 
                className="p-2 border border-slate-200 rounded-lg text-xs w-full focus:outline-none focus:ring-2 focus:ring-blue-100 text-slate-600 font-medium"
            />
        </div>
        <div className="relative flex-1">
            <span className="absolute -top-2 left-2 bg-white px-1 text-[10px] font-bold text-slate-400 pointer-events-none">Até</span>
            <input 
                type="date" 
                value={endDate} 
                onChange={e => setEndDate(e.target.value)} 
                className="p-2 border border-slate-200 rounded-lg text-xs w-full focus:outline-none focus:ring-2 focus:ring-blue-100 text-slate-600 font-medium"
            />
        </div>
    </div>
);


// --- COMPONENTES PRINCIPAL ---

interface MoodDiaryProps {
  userProfile: UserProfile | null;
  preSelectedChildId?: string | null;
  readOnly?: boolean;
}

type DiaryMode = 'MOOD' | 'BEHAVIOR';

const MoodDiary: React.FC<MoodDiaryProps> = ({ userProfile, preSelectedChildId, readOnly = false }) => {
  const isChildProfile = userProfile?.profileType === ProfileType.CHILD;
  const isAdultProfile = userProfile?.profileType === ProfileType.ADULT;

  const [diaryMode, setDiaryMode] = useState<DiaryMode>('MOOD');

  const canRegister = useMemo(() => {
    if (readOnly) return false;
    return userProfile?.profileType !== ProfileType.ADULT;
  }, [userProfile, readOnly]); 

  const targetUid = useMemo(() => {
    if (preSelectedChildId) return preSelectedChildId;
    if (!userProfile) return null;
    if (userProfile.profileType === ProfileType.ADULT && userProfile.manages && userProfile.manages.length > 0) {
        return userProfile.manages[0];
    }
    return userProfile.uid;
  }, [userProfile, preSelectedChildId]);

  const isManagingChild = (userProfile?.profileType === ProfileType.ADULT && targetUid !== userProfile?.uid) || preSelectedChildId;

  const [childDisplayName, setChildDisplayName] = useState<string | null>(null);
  const [showSchoolTab, setShowSchoolTab] = useState(false);

  const initialActiveTab = canRegister ? 'register' : 'history';
  // activeTab type changed to remove calm_history
  const [activeTab, setActiveTab] = useState<'register' | 'history' | 'analysis' | 'school_history'>(initialActiveTab);

  const [mood, setMood] = useState<MoodType | null>(null);
  const [notes, setNotes] = useState('');
  const [period, setPeriod] = useState<'Manhã' | 'Tarde' | 'Noite'>('Manhã');
  const [entryDate, setEntryDate] = useState(TODAY_STRING); 
  const [emotionExplanation, setEmotionExplanation] = useState("Selecione um humor.");

  const [history, setHistory] = useState<MoodEntry[]>([] as MoodEntry[]);
  // Removed calmHistory state
  const [schoolLogs, setSchoolLogs] = useState<SchoolLog[]>([]);
  const [schoolMedLogs, setSchoolMedLogs] = useState<SchoolMedicationLog[]>([]);
  const [schoolHistoryView, setSchoolHistoryView] = useState<'behavior' | 'medication'>('behavior');

  const [displayState, setDisplayState] = useState<'form' | 'insight'>('form');
  const [currentInsight, setCurrentInsight] = useState('');
  const [isAnalysing, setIsAnalysing] = useState(false);

  // Audio Playback
  const [isPlaying, setIsPlaying] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const [prefetchedAudioBuffer, setPrefetchedAudioBuffer] = useState<AudioBuffer | null>(null);

  // Explanation Audio
  const [isSpeakingExplanation, setIsSpeakingExplanation] = useState(false);
  const [isSynthesizingExplanation, setIsSynthesizingExplanation] = useState(false);
  const explanationAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const [explanationAudioBuffer, setExplanationAudioBuffer] = useState<AudioBuffer | null>(null);

  // Speech Recognition
  const [isListening, setIsListening] = useState(false);
  const recognitionRef = useRef<any>(null);
  const textBaseRef = useRef<string>('');

  // 🆕 History Filters (Global Dates)
  const [moodFilter, setMoodFilter] = useState<string | null>(null);
  const [startDate, setStartDate] = useState<string>('');
  const [endDate, setEndDate] = useState<string>('');

  // Delete Confirmation
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [entryToDelete, setEntryToDelete] = useState<{ id: string, dateString: string } | null>(null);

  const [speakingHistoryId, setSpeakingHistoryId] = useState<string | null>(null);
  const historyAudioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const [isHistoryAudioLoading, setIsHistoryAudioLoading] = useState(false);
  const historyAudioCache = useRef<Record<string, AudioBuffer>>({});

  const stopAllAudio = useCallback(() => {
      if (isListening && recognitionRef.current) recognitionRef.current.stop();
      if (audioSourceRef.current) { audioSourceRef.current.stop(); setIsPlaying(false); audioSourceRef.current = null; }
      if (explanationAudioSourceRef.current) { explanationAudioSourceRef.current.stop(); setIsSpeakingExplanation(false); explanationAudioSourceRef.current = null; }
      if (historyAudioSourceRef.current) { historyAudioSourceRef.current.stop(); setSpeakingHistoryId(null); historyAudioSourceRef.current = null; }
      if (audioContextRef.current && audioContextRef.current.state === 'running') { audioContextRef.current.suspend(); }
  }, [isListening]);

  useEffect(() => {
    if (isManagingChild && targetUid) {
        const fetchChildData = async () => {
            try {
                const profileSnap = await db.collection("users").doc(targetUid).collection("child_profile").doc("main").get();
                if(profileSnap.exists) {
                    const data = profileSnap.data();
                    if (data) {
                        setChildDisplayName(data.childName || 'Criança');
                        setShowSchoolTab(data.showSchoolHistoryToGuardian || false);
                    }
                    return;
                }
                const docSnap = await db.collection("users").doc(targetUid).get();
                if (docSnap.exists) setChildDisplayName(docSnap.data()?.displayName || 'Criança');
                else setChildDisplayName('Criança Desconhecida');
            } catch (error) { console.error("Erro ao buscar dados da criança:", error); setChildDisplayName('Erro ao carregar'); }
        };
        fetchChildData();
    } else { setChildDisplayName(null); setShowSchoolTab(false); }
  }, [isManagingChild, targetUid]); 

  useEffect(() => {
    if (!targetUid) return;
    const unsubscribeMood = db.collection("users").doc(targetUid).collection("mood_entries")
      .orderBy("timestamp", "desc")
      .onSnapshot((snapshot) => {
          const entries = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MoodEntry));
          setHistory(entries);
      });
    return () => unsubscribeMood();
  }, [targetUid]);

  useEffect(() => {
      if (activeTab === 'school_history' && targetUid) {
          const unsubscribeSchool = db.collection("users").doc(targetUid).collection("school_logs")
            .orderBy("date", "desc")
            .onSnapshot((snapshot) => {
                const logs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SchoolLog));
                setSchoolLogs(logs);
            });
          const unsubscribeSchoolMeds = db.collection("users").doc(targetUid).collection("school_medication_logs")
            .orderBy("timestamp", "desc")
            .onSnapshot((snapshot) => {
                const logs = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SchoolMedicationLog));
                setSchoolMedLogs(logs);
            });
          return () => { unsubscribeSchool(); unsubscribeSchoolMeds(); };
      }
  }, [activeTab, targetUid]);

  // Removed useEffect for calm_history

  // Speech Recognition Setup (Same as before)
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = false; recognition.interimResults = false; recognition.lang = 'pt-BR';
      recognition.onstart = () => setIsListening(true);
      recognition.onend = () => { setTimeout(() => { if (isListening) setIsListening(false); }, 100); };
      recognition.onerror = (event: any) => { console.error("Speech Recognition Error:", event.error); setIsListening(false); };
      recognition.onresult = (event: any) => {
        let transcript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) { if (event.results[i].isFinal) transcript += event.results[i][0].transcript; }
        if (transcript) setNotes(prev => (prev && !prev.endsWith(' ')) ? prev + ' ' + transcript : prev + transcript);
      };
      recognitionRef.current = recognition;
    }
    return () => { if (recognitionRef.current) recognitionRef.current.stop(); };
  }, [isListening]); 

  useEffect(() => { return () => { stopAllAudio(); if (audioContextRef.current && audioContextRef.current.state !== 'closed') audioContextRef.current.close(); }; }, [stopAllAudio]);

  useEffect(() => {
    const fetchExplanation = async () => {
        stopAllAudio(); setExplanationAudioBuffer(null);
        if (!mood) { setEmotionExplanation("Selecione um humor."); return; }
        setIsSynthesizingExplanation(true);
        try {
            const text = EMOTION_DETAILS[mood].explanation;
            setEmotionExplanation(text);
            const base64Audio = await generateSpeech(text);
            if (base64Audio) {
                if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
                const ctx = audioContextRef.current;
                const buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
                setExplanationAudioBuffer(buffer);
            }
        } catch (err) { console.error(err); } finally { setIsSynthesizingExplanation(false); }
    };
    fetchExplanation();
  }, [mood, stopAllAudio]);

  useEffect(() => {
    if (userProfile?.profileType === ProfileType.ADULT || readOnly) { if (activeTab === 'register') setActiveTab('history'); }
    else if (isChildProfile && activeTab === 'analysis') setActiveTab('register');
  }, [isChildProfile, activeTab, userProfile?.profileType, readOnly]);

  const isEntryToday = (entryDateString: string | undefined): boolean => {
    if (!entryDateString) return false;
    return entryDateString === TODAY_STRING;
  };

  const isEntryDuplicate = useMemo(() => {
    if (!entryDate || !period) return false;
    return history.some(entry => entry.dateString === entryDate && entry.period === period);
  }, [history, entryDate, period]);

  const toggleListening = () => {
    if (!recognitionRef.current) return;
    stopAllAudio();
    if (isListening) { recognitionRef.current.stop(); setIsListening(false); } 
    else { textBaseRef.current = notes; if (audioContextRef.current && audioContextRef.current.state === 'suspended') audioContextRef.current.resume(); recognitionRef.current.start(); }
  };

  const handleSpeakExplanation = () => {
    if (isSpeakingExplanation) { stopAllAudio(); return; }
    if (!explanationAudioBuffer || !audioContextRef.current) return;
    stopAllAudio();
    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') ctx.resume();
    const source = ctx.createBufferSource(); source.buffer = explanationAudioBuffer; source.connect(ctx.destination);
    source.onended = () => { setIsSpeakingExplanation(false); explanationAudioSourceRef.current = null; };
    source.start(); explanationAudioSourceRef.current = source; setIsSpeakingExplanation(true);
  };

  const handlePlayHistoryInsight = useCallback(async (entry: MoodEntry) => {
      if (!entry.aiFeedback) return;
      if (speakingHistoryId === entry.id) { stopAllAudio(); return; }
      stopAllAudio();
      setIsHistoryAudioLoading(true); setSpeakingHistoryId(entry.id);
      try {
          if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
          const ctx = audioContextRef.current; if (ctx.state === 'suspended') ctx.resume();
          let buffer: AudioBuffer;
          if (historyAudioCache.current[entry.id]) { buffer = historyAudioCache.current[entry.id]; } 
          else {
              const base64Audio = await generateSpeech(entry.aiFeedback);
              if (!base64Audio) throw new Error("Falha na API TTS");
              buffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
              historyAudioCache.current[entry.id] = buffer;
          }
          const source = ctx.createBufferSource(); source.buffer = buffer; source.connect(ctx.destination);
          source.onended = () => { setSpeakingHistoryId(null); historyAudioSourceRef.current = null; };
          source.start(); historyAudioSourceRef.current = source;
      } catch (error) { console.error("Erro ao tocar histórico:", error); setSpeakingHistoryId(null); alert("Não foi possível reproduzir o áudio."); } 
      finally { setIsHistoryAudioLoading(false); }
  }, [speakingHistoryId, stopAllAudio]);

  const handleConfirmDeleteStart = (entryId: string, entryDateString: string) => {
      if (!isEntryToday(entryDateString)) { alert(`Você só pode apagar registros feitos no dia de hoje (${new Date().toLocaleDateString('pt-BR')}).`); return; }
      setEntryToDelete({ id: entryId, dateString: entryDateString }); setShowDeleteConfirm(true);
  };

  const handleConfirmDeleteExecute = useCallback(async () => {
      if (!targetUid || !entryToDelete) { setShowDeleteConfirm(false); setEntryToDelete(null); return; }
      try { await db.collection("users").doc(targetUid).collection("mood_entries").doc(entryToDelete.id).delete(); } 
      catch (error) { console.error("Erro ao apagar registro:", error); } 
      finally { setShowDeleteConfirm(false); setEntryToDelete(null); }
  }, [targetUid, entryToDelete]);

  const handleConfirmDeleteCancel = () => { setShowDeleteConfirm(false); setEntryToDelete(null); };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!canRegister || !mood || !targetUid || entryDate > TODAY_STRING || isEntryDuplicate) return;
    stopAllAudio(); setIsAnalysing(true);
    try {
        let aiFeedback = "Continue firme! 🌟";
        if (process.env.API_KEY) {
            const userRole = isChildProfile ? 'uma criança' : 'um adulto'; 
            const prompt = `Aja como um psicólogo empático para ${userRole}. O usuário está sentindo: ${EMOTION_DETAILS[mood].label}. Período: ${period}. Notas: "${notes}". Responda com um insight curto, positivo e acolhedor (máximo 2 frases).`;
            const result = await ai.models.generateContent({ model: 'gemini-2.5-flash', contents: [{ role: "user", parts: [{ text: prompt }] }] });
            if (result.text) aiFeedback = result.text.trim();
        }
        const moodEntry: Omit<MoodEntry, 'id'> = { userId: targetUid, timestamp: Date.now(), dateString: entryDate, mood, notes, period, aiFeedback };
        if(targetUid) await db.collection("users").doc(targetUid).collection("mood_entries").add(moodEntry);
        else throw new Error("UID de destino não encontrado.");
        setCurrentInsight(aiFeedback); setDisplayState('insight'); setPrefetchedAudioBuffer(null);
        const base64Audio = await generateSpeech(aiFeedback);
        if (base64Audio) {
            if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const buffer = await decodeAudioData(decode(base64Audio), audioContextRef.current, 24000, 1);
            setPrefetchedAudioBuffer(buffer);
        }
    } catch (error: any) { console.error("Erro ao salvar:", error); alert(`Falha ao registrar humor: ${error.message || 'Erro desconhecido'}`); } 
    finally { setIsAnalysing(false); }
  };

  const handlePlayInsight = () => {
    if (isPlaying) { stopAllAudio(); return; }
    if (!prefetchedAudioBuffer || !audioContextRef.current) return;
    stopAllAudio();
    const ctx = audioContextRef.current; if (ctx.state === 'suspended') ctx.resume();
    const source = ctx.createBufferSource(); source.buffer = prefetchedAudioBuffer; source.connect(ctx.destination);
    source.onended = () => { setIsPlaying(false); audioSourceRef.current = null; };
    source.start(); audioSourceRef.current = source; setIsPlaying(true);
  };

  const handleReset = () => {
      setMood(null); setNotes(''); setCurrentInsight(''); setDisplayState('form'); setPrefetchedAudioBuffer(null); setEmotionExplanation("Selecione um humor."); setEntryDate(TODAY_STRING); setPeriod('Manhã');           
  };

  const chartData = useMemo(() => {
    if (isChildProfile || history.length === 0) return [];
    const grouped = history.reduce<Record<string, { sum: number; count: number }>>((acc, entry) => {
      const d = entry.dateString || ''; if (!d) return acc;
      if (!acc[d]) acc[d] = { sum: 0, count: 0 };
      const cat = EMOTION_DETAILS[entry.mood]?.category || 'Médio';
      acc[d].sum += MOOD_CATEGORY_VALUES[cat]; acc[d].count += 1; return acc;
    }, {});
    return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0])).slice(-30).map(([date, val]) => {
        const v = val as { sum: number; count: number };
        return { date: date.split('-').slice(1).reverse().join('/'), val: Number((v.sum / v.count).toFixed(2)) };
    });
  }, [history, isChildProfile]);

  const crisisData = useMemo(() => {
    if (isChildProfile) return [];
      const counts: Record<string, number> = { 'Manhã': 0, 'Tarde': 0, 'Noite': 0 };
      history.filter(e => EMOTION_DETAILS[e.mood]?.category === 'Ruim').forEach(e => { if (counts[e.period] !== undefined) counts[e.period]++; });
      return Object.keys(PERIOD_ORDER).map(periodName => ({ name: periodName, value: counts[periodName as keyof typeof counts] || 0 })) as { name: 'Manhã' | 'Tarde' | 'Noite', value: number }[];
  }, [history, isChildProfile]);

  // --- FILTROS APLICADOS ---

  const filteredHistory = useMemo(() => {
    let result: MoodEntry[] = history.filter(e => {
        const entryMoodCategory = EMOTION_DETAILS[e.mood]?.category;
        if (moodFilter && entryMoodCategory !== moodFilter) return false;
        // Date Range
        if (startDate && e.dateString && e.dateString < startDate) return false;
        if (endDate && e.dateString && e.dateString > endDate) return false;
        return true;
    });
    result.sort((a, b) => {
        const dateA = a.dateString || ''; const dateB = b.dateString || '';
        if (dateA !== dateB) return dateB.localeCompare(dateA); 
        const periodOrderA = PERIOD_ORDER[a.period] || 99; const periodOrderB = PERIOD_ORDER[b.period] || 99;
        return periodOrderA - periodOrderB;
    });
    return result;
  }, [history, moodFilter, startDate, endDate]);

  const filteredSchoolLogs = useMemo(() => {
      let result = schoolLogs;
      if (startDate) result = result.filter(e => e.date >= startDate);
      if (endDate) result = result.filter(e => e.date <= endDate);
      return result;
  }, [schoolLogs, startDate, endDate]);

  const filteredSchoolMedLogs = useMemo(() => {
      let result = schoolMedLogs;
      if (startDate) result = result.filter(e => e.date >= startDate);
      if (endDate) result = result.filter(e => e.date <= endDate);
      return result;
  }, [schoolMedLogs, startDate, endDate]);

  const moodOptions = Object.values(MoodType).map(m => ({ type: m, ...EMOTION_DETAILS[m] }));

  // SE FOR ADULTO E ESTIVER NO MODO COMPORTAMENTAL (E NÃO READONLY)
  if (isAdultProfile && diaryMode === 'BEHAVIOR' && !readOnly) {
      return (
          <div className="p-4 max-w-md mx-auto pb-24 font-sans">
              {isManagingChild && (
                  <div className="bg-blue-50 border border-blue-200 text-blue-800 text-sm px-4 py-2 rounded-lg flex items-center gap-2 mb-4">
                      <span>📘</span><span>Registrando comportamento de: <strong>{childDisplayName || 'Carregando...'}</strong></span>
                  </div>
              )}
              <div className="bg-slate-100 p-1 rounded-xl flex mb-6 shadow-inner">
                  <button onClick={() => setDiaryMode('MOOD')} className="flex-1 py-2 rounded-lg text-sm font-bold text-slate-500 hover:text-slate-700 transition-colors flex items-center justify-center gap-1"><BookHeart className="w-4 h-4"/> <span className="hidden sm:inline">Humor</span></button>
                  <button onClick={() => setDiaryMode('BEHAVIOR')} className="flex-1 py-2 rounded-lg text-sm font-bold bg-white text-blue-600 shadow-sm flex items-center justify-center gap-1"><ClipboardList className="w-4 h-4"/> <span className="hidden sm:inline">Comp.</span></button>
              </div>
              {userProfile && <BehaviorDiary userProfile={userProfile} />}
          </div>
      );
  }

  return (
    <div className="p-4 max-w-md mx-auto pb-24 font-sans">

        {isManagingChild && !readOnly && (
            <div className="bg-blue-50 border border-blue-200 text-blue-800 text-sm px-4 py-2 rounded-lg flex items-center gap-2 mb-4">
                <span>📘</span><span>Visualizando humor de: <strong>{childDisplayName || 'Carregando nome...'}</strong></span>
            </div>
        )}

        {isAdultProfile && !readOnly && (
            <div className="bg-slate-100 p-1 rounded-xl flex mb-6 shadow-inner">
                <button onClick={() => setDiaryMode('MOOD')} className="flex-1 py-2 rounded-lg text-sm font-bold bg-white text-blue-600 shadow-sm flex items-center justify-center gap-1"><BookHeart className="w-4 h-4"/> <span className="hidden sm:inline">Humor</span></button>
                <button onClick={() => setDiaryMode('BEHAVIOR')} className="flex-1 py-2 rounded-lg text-sm font-bold text-slate-500 hover:text-slate-700 transition-colors flex items-center justify-center gap-1"><ClipboardList className="w-4 h-4"/> <span className="hidden sm:inline">Comp.</span></button>
            </div>
        )}

      {!readOnly && (
          <div className="flex justify-between gap-2 p-2 bg-white rounded-3xl w-full shadow-lg border border-slate-100 mb-6 overflow-x-auto">
            {canRegister && (
                <button onClick={() => setActiveTab('register')} className={`flex flex-col items-center justify-center transition-all duration-200 group flex-1 min-w-[70px] ${activeTab === 'register' ? 'scale-105' : 'opacity-70 hover:opacity-100'}`}>
                    <MoodDynamicTabIcon tab="register" /><span className={`text-xs mt-1 font-medium whitespace-nowrap ${activeTab === 'register' ? 'text-pink-600 font-bold' : 'text-slate-500'}`}>Registrar</span>
                </button>
            )}
            <button onClick={() => setActiveTab('history')} className={`flex flex-col items-center justify-center transition-all duration-200 group flex-1 min-w-[70px] ${activeTab === 'history' ? 'scale-105' : 'opacity-70 hover:opacity-100'}`}>
                <MoodDynamicTabIcon tab="history" /><span className={`text-xs mt-1 font-medium whitespace-nowrap ${activeTab === 'history' ? 'text-blue-600 font-bold' : 'text-slate-500'}`}>Histórico</span>
            </button>
            {showSchoolTab && (
                <button onClick={() => setActiveTab('school_history')} className={`flex flex-col items-center justify-center transition-all duration-200 group flex-1 min-w-[70px] ${activeTab === 'school_history' ? 'scale-105' : 'opacity-70 hover:opacity-100'}`}>
                    <MoodDynamicTabIcon tab="school_history" /><span className={`text-xs mt-1 font-medium whitespace-nowrap ${activeTab === 'school_history' ? 'text-violet-600 font-bold' : 'text-slate-500'}`}>Escola</span>
                </button>
            )}
            {userProfile?.profileType !== ProfileType.CHILD && (
                <button onClick={() => setActiveTab('analysis')} className={`flex flex-col items-center justify-center transition-all duration-200 group flex-1 min-w-[70px] ${activeTab === 'analysis' ? 'scale-105' : 'opacity-70 hover:opacity-100'}`}>
                    <MoodDynamicTabIcon tab="analysis" /><span className={`text-xs mt-1 font-medium whitespace-nowrap ${activeTab === 'analysis' ? 'text-purple-600 font-bold' : 'text-slate-500'}`}>Análise</span>
                </button>
            )}
          </div>
      )}

      {/* REGISTER TAB */}
      {activeTab === 'register' && canRegister && (
        <div className="animate-in fade-in slide-in-from-bottom-2">
            {displayState === 'form' ? (
                <>
                    <div className="grid grid-cols-3 gap-2 mb-6">
                        {moodOptions.map((opt) => (
                            <button key={opt.type} onClick={() => setMood(opt.type)} className={`flex flex-col items-center justify-center p-1 rounded-2xl transition-all aspect-square relative overflow-hidden group ${mood === opt.type ? 'ring-4 ring-offset-2 ring-blue-200 scale-105 z-10 shadow-lg' : 'opacity-90 hover:opacity-100 hover:scale-105'}`} style={{ backgroundColor: opt.color }}>
                                <div className="absolute inset-2 border-2 border-white/20 rounded-xl pointer-events-none"></div>
                                <span className="text-3xl mb-1">{opt.icon}</span>
                                <span className="text-white font-bold text-[10px]">{opt.label}</span>
                            </button>
                        ))}
                    </div>
                    <div className="mb-6">
                        {mood ? <InsightBox mood={mood} text={emotionExplanation} onSpeakerClick={handleSpeakExplanation} isSpeaking={isSpeakingExplanation} isLoading={isSynthesizingExplanation}/> : <div className="bg-slate-100 p-6 rounded-2xl border border-slate-200 text-center text-slate-500 text-sm">Selecione uma emoção acima para começar.</div>}
                    </div>
                    {mood && (
                        <form onSubmit={handleSubmit} className="space-y-5 bg-white rounded-xl">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5 ml-1">Data</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none"><CalendarIcon className="w-5 h-5 text-slate-400" /></div>
                                    <input type="date" value={entryDate} onChange={e => setEntryDate(e.target.value)} max={TODAY_STRING} className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-100 text-slate-700" />
                                </div>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5 ml-1">Período</label>
                                <div className="flex bg-slate-100 p-1.5 rounded-xl">
                                    {['Manhã', 'Tarde', 'Noite'].map(p => (
                                        <button key={p} type="button" onClick={() => setPeriod(p as any)} className={`flex-1 py-2.5 text-xs font-bold rounded-lg transition-all ${period === p ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>{p}</button>
                                    ))}
                                </div>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-1.5 ml-1">Notas (Opcional)</label>
                                <div className="relative">
                                    <textarea value={notes} onChange={e => setNotes(e.target.value)} rows={3} className="w-full p-3 border border-slate-200 rounded-xl resize-none" placeholder="Como você se sente?" />
                                    <button type="button" onClick={toggleListening} className={`absolute right-2 top-2 p-2 rounded-full transition-colors ${isListening ? 'bg-red-500 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}>{isListening ? <StopCircle className="w-4 h-4" /> : <Mic className="w-4 h-4" />}</button>
                                </div>
                            </div>
                            <button type="submit" disabled={isAnalysing || isEntryDuplicate || !mood} className={`w-full py-3 rounded-xl text-white font-bold ${isAnalysing || isEntryDuplicate || !mood ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}>
                                {isAnalysing ? <><Loader2 className="w-5 h-5 animate-spin inline mr-2"/> Analisando...</> : isEntryDuplicate ? 'Registro já existe' : 'Registrar'}
                            </button>
                        </form>
                    )}
                </>
            ) : (
                <div className="space-y-6">
                    <h2 className="text-2xl font-bold text-gray-800 text-center">Registro Salvo!</h2>
                    <InsightBox mood={mood || MoodType.CALM} text={currentInsight} onSpeakerClick={handlePlayInsight} isSpeaking={isPlaying} isLoading={isAnalysing}/>
                    <button onClick={handleReset} className="w-full py-3 rounded-xl font-bold text-blue-600 bg-blue-50 hover:bg-blue-100">Novo Registro</button>
                </div>
            )}
        </div>
      )}

      {/* HISTORY TAB */}
      {activeTab === 'history' && (
        <div className="animate-in fade-in">
          <div className="flex flex-col md:flex-row gap-3 mb-6 bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
              <div className="flex items-center gap-2 w-full md:w-auto">
                  <Filter className="w-4 h-4 text-slate-400" />
                  <select value={moodFilter || ''} onChange={e => setMoodFilter(e.target.value || null)} className="flex-1 p-2 border border-slate-200 rounded-lg text-xs focus:outline-none focus:ring-2 focus:ring-blue-100 bg-transparent font-bold text-slate-600">
                    <option value="">Todos os Humores</option>
                    {Object.keys(MOOD_CATEGORY_VALUES).map(k => <option key={k} value={k}>{k}</option>)}
                  </select>
              </div>
              <DateRangeFilter startDate={startDate} setStartDate={setStartDate} endDate={endDate} setEndDate={setEndDate} />
          </div>

          <div className="space-y-3">
            {filteredHistory.length === 0 ? <p className="text-center text-slate-500">Nenhum registro encontrado.</p> : filteredHistory.map(entry => {
                const details = EMOTION_DETAILS[entry.mood];
                const isToday = isEntryToday(entry.dateString);
                const isThisPlaying = speakingHistoryId === entry.id && !isHistoryAudioLoading;
                const isThisLoading = speakingHistoryId === entry.id && isHistoryAudioLoading;

                return (
                    <div key={entry.id} className="p-4 bg-white rounded-xl shadow-sm border-l-4" style={{ borderColor: details.color }}>
                        <div className="flex justify-between items-center mb-2">
                            <div className="flex items-center gap-2">
                                <span className="text-2xl">{details.icon}</span>
                                <div>
                                    <p className="font-bold text-slate-800 text-sm">{details.label}</p>
                                    <p className="text-xs text-slate-500">{new Date(entry.dateString).toLocaleDateString('pt-BR', {timeZone: 'UTC'})} - {entry.period}</p>
                                </div>
                            </div>
                            {isToday && canRegister && (
                                <button onClick={() => handleConfirmDeleteStart(entry.id, entry.dateString)} className="text-red-400 hover:text-red-600"><Trash2 className="w-4 h-4" /></button>
                            )}
                        </div>
                        {entry.notes && <p className="text-sm text-slate-600 italic mb-2">"{entry.notes}"</p>}
                        {entry.aiFeedback && (
                            <div className="mt-3 pt-3 border-t border-slate-100 flex items-start gap-3">
                                <div className="bg-blue-50 p-2 rounded-full"><Bot className="w-4 h-4 text-blue-600" /></div>
                                <div className="flex-1">
                                    <p className="text-xs font-bold text-blue-700 mb-0.5">Insight do Robô</p>
                                    <p className="text-sm text-slate-700 leading-snug">{entry.aiFeedback}</p>
                                </div>
                                <button onClick={() => handlePlayHistoryInsight(entry)} disabled={isHistoryAudioLoading && speakingHistoryId !== entry.id} className={`p-2 rounded-full transition-colors ${isThisPlaying ? 'bg-red-100 text-red-600 hover:bg-red-200' : 'bg-slate-100 text-slate-600 hover:bg-blue-100 hover:text-blue-600'}`} title={isThisPlaying ? "Parar" : "Ouvir"}>
                                    {isThisLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : isThisPlaying ? <StopCircle className="w-4 h-4" /> : <Volume2 className="w-4 h-4" />}
                                </button>
                            </div>
                        )}
                    </div>
                );
            })}
            <DeleteConfirmModal isOpen={showDeleteConfirm} onClose={handleConfirmDeleteCancel} onConfirm={handleConfirmDeleteExecute} entryDate={entryToDelete?.dateString} />
          </div>
        </div>
      )}

      {/* 🆕 SCHOOL HISTORY TAB */}
      {activeTab === 'school_history' && showSchoolTab && (
          <div className="animate-in fade-in space-y-4">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2"><GraduationCap className="w-5 h-5 text-violet-500" /> Histórico Escolar</h3>

              <div className="bg-slate-50 p-3 rounded-xl border border-slate-200 shadow-sm mb-4">
                  <div className="flex flex-col gap-3">
                    <div className="flex bg-white p-1 rounded-lg border border-slate-100 shadow-sm">
                        <button onClick={() => setSchoolHistoryView('behavior')} className={`flex-1 py-2 rounded text-xs font-bold transition-all flex items-center justify-center gap-2 ${schoolHistoryView === 'behavior' ? 'bg-violet-100 text-violet-700' : 'text-slate-500 hover:text-slate-700'}`}><Activity className="w-3 h-3"/> Comportamental</button>
                        <button onClick={() => setSchoolHistoryView('medication')} className={`flex-1 py-2 rounded text-xs font-bold transition-all flex items-center justify-center gap-2 ${schoolHistoryView === 'medication' ? 'bg-pink-100 text-pink-700' : 'text-slate-500 hover:text-slate-700'}`}><Pill className="w-3 h-3"/> Medicação</button>
                    </div>
                    <DateRangeFilter startDate={startDate} setStartDate={setStartDate} endDate={endDate} setEndDate={setEndDate} />
                  </div>
              </div>

              {schoolHistoryView === 'behavior' ? (
                  <>
                      {filteredSchoolLogs.length === 0 ? (
                          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-slate-300 text-slate-400"><GraduationCap className="w-12 h-12 mx-auto mb-2 opacity-50" /><p>Nenhum registro escolar.</p></div>
                      ) : (
                          filteredSchoolLogs.map(log => (
                              <div key={log.id} className="p-4 bg-white border border-slate-200 rounded-xl shadow-sm">
                                  <div className="flex justify-between items-center mb-3">
                                      <span className="text-xs font-bold bg-purple-50 text-purple-700 px-2 py-1 rounded">{new Date(log.date + 'T12:00:00').toLocaleDateString('pt-BR')}</span>
                                      {log.dysregulationCount > 0 && (<span className="text-[10px] bg-red-100 text-red-600 px-2 py-0.5 rounded-full font-bold flex items-center gap-1"><AlertTriangle className="w-3 h-3" /> {log.dysregulationCount} Ocorrência(s)</span>)}
                                  </div>
                                  <div className="grid grid-cols-2 gap-3 mb-3">
                                      <div className="bg-slate-50 p-2 rounded-lg"><p className="text-[10px] text-slate-500 font-bold uppercase mb-0.5">Social</p><p className="text-sm font-semibold text-slate-800">{log.socialInteraction}</p></div>
                                      <div className="bg-slate-50 p-2 rounded-lg"><p className="text-[10px] text-slate-500 font-bold uppercase mb-0.5">Participação</p><p className="text-sm font-semibold text-slate-800">{log.participation}</p></div>
                                  </div>
                                  {log.generalNotes && (<div className="text-sm border-t border-slate-100 pt-2 mt-2"><p className="text-xs font-bold text-slate-500 mb-1">Observações da Escola:</p><p className="text-slate-700 italic">"{log.generalNotes}"</p></div>)}
                              </div>
                          ))
                      )}
                  </>
              ) : (
                  <>
                      {filteredSchoolMedLogs.length === 0 ? (
                          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-pink-200 text-slate-400"><Pill className="w-12 h-12 mx-auto mb-2 opacity-50 text-pink-300" /><p>Nenhum registro de medicação.</p></div>
                      ) : (
                          filteredSchoolMedLogs.map(log => (
                              <div key={log.id} className="p-3 bg-white border border-pink-100 rounded-xl shadow-sm relative overflow-hidden">
                                  <div className="absolute left-0 top-0 bottom-0 w-1 bg-pink-400"></div>
                                  <div className="pl-3">
                                      <div className="flex justify-between items-start mb-1">
                                          <div className="flex items-center gap-2"><span className="text-xs font-bold bg-pink-50 text-pink-700 px-2 py-1 rounded">{new Date(log.date + 'T12:00:00').toLocaleDateString('pt-BR')}</span><span className="text-xs font-medium text-slate-500 flex items-center gap-1"><Clock className="w-3 h-3"/> {log.time}</span></div>
                                      </div>
                                      <div className="flex items-center gap-2 mb-1"><Pill className="w-4 h-4 text-pink-500"/><span className="font-bold text-slate-800">{log.medicationName}</span></div>
                                      <p className="text-xs text-slate-600">Dosagem: <span className="font-semibold">{log.dosage}</span></p>
                                      {log.notes && (<p className="text-xs text-slate-500 mt-1 italic">Obs: {log.notes}</p>)}
                                  </div>
                              </div>
                          ))
                      )}
                  </>
              )}
          </div>
      )}

      {/* ANALYSIS TAB (Se não for criança) */}
      {activeTab === 'analysis' && userProfile?.profileType !== 'CHILD' && (
           <div className="animate-in fade-in space-y-6">
                <h2 className="text-xl font-bold mb-4">📈 Tendência Média do Humor (Últimos 30 dias)</h2>
                <p className="text-sm text-slate-500 mb-2">1 = Ruim, 2 = Médio, 3 = Bom</p>
                <div className="h-64 w-full bg-white p-2 rounded-xl shadow-sm border border-slate-100">
                  {chartData.length > 1 ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <LineChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                              <XAxis dataKey="date" tick={{fontSize: 10}}/>
                              <YAxis domain={[1, 3]} hide />
                              <Tooltip />
                              <Line type="monotone" dataKey="val" stroke="#3B82F6" strokeWidth={3} dot={false}/>
                          </LineChart>
                      </ResponsiveContainer>
                  ) : (
                      <p className="h-full flex items-center justify-center text-slate-400">Dados insuficientes para o gráfico.</p>
                  )}
                </div>

                <h2 className="text-xl font-bold mt-8 mb-4">🚨 Eventos de Humor Ruim por Período</h2>
                <div className="h-64 w-full bg-white p-2 rounded-xl shadow-sm border border-slate-100">
                  {crisisData.length > 0 && crisisData.some(d => d.value > 0) ? (
                      <ResponsiveContainer width="100%" height="100%">
                          <BarChart data={crisisData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                              <XAxis dataKey="name" />
                              <YAxis allowDecimals={false} />
                              <Tooltip />
                              <Bar dataKey="value" name="Crises" fill={MOOD_CATEGORY_COLORS['Ruim']} radius={[4, 4, 0, 0]}/>
                          </BarChart>
                      </ResponsiveContainer>
                  ) : (
                      <p className="h-full flex items-center justify-center text-slate-400">Nenhum registro de humor "Ruim" para análise.</p>
                  )}
                </div>
           </div>
      )}
    </div>
  );
};

export default MoodDiary;

import React, { useState, useEffect } from 'react';
import { UserProfile, BehaviorEntry, BehaviorEventType, CrisisIntensity } from '../types';
import { db } from '../services/firebase';
import { AlertTriangle, Utensils, Moon, Zap, AlertCircle, Gift, Save, Clock, Trash2, Calendar } from 'lucide-react';

interface BehaviorDiaryProps {
  userProfile: UserProfile;
  preSelectedChildId?: string | null; 
  readOnly?: boolean; 
  startDate?: string; // 🆕 Filtro Data Início
  endDate?: string;   // 🆕 Filtro Data Fim
}

const EVENT_TYPES: { id: BehaviorEventType; label: string; icon: React.ReactNode; color: string }[] = [
  { id: 'CRISIS', label: 'Crise', icon: <AlertTriangle />, color: 'bg-red-100 text-red-600 border-red-200' },
  { id: 'FOOD', label: 'Alimentação', icon: <Utensils />, color: 'bg-green-100 text-green-600 border-green-200' },
  { id: 'SLEEP', label: 'Sono', icon: <Moon />, color: 'bg-blue-100 text-blue-600 border-blue-200' },
  { id: 'HYPERFOCUS', label: 'Hiperfoco', icon: <Zap />, color: 'bg-purple-100 text-purple-600 border-purple-200' },
  { id: 'TRIGGER', label: 'Gatilho', icon: <AlertCircle />, color: 'bg-orange-100 text-orange-600 border-orange-200' },
  { id: 'REINFORCER', label: 'Reforçador', icon: <Gift />, color: 'bg-pink-100 text-pink-600 border-pink-200' },
];

const INTENSITIES: { id: CrisisIntensity; label: string; color: string }[] = [
  { id: 'LEVE', label: 'Leve', color: 'bg-yellow-100 text-yellow-700' },
  { id: 'MODERADA', label: 'Moderada', color: 'bg-orange-100 text-orange-700' },
  { id: 'INTENSA', label: 'Intensa', color: 'bg-red-100 text-red-700' },
];

// Helper para obter data local formatada (YYYY-MM-DD)
const getLocalTodayString = (): string => {
  const today = new Date();
  const year = today.getFullYear();
  const month = String(today.getMonth() + 1).padStart(2, '0');
  const day = String(today.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const BehaviorDiary: React.FC<BehaviorDiaryProps> = ({ userProfile, preSelectedChildId, readOnly = false, startDate, endDate }) => {
  const [selectedType, setSelectedType] = useState<BehaviorEventType | null>(null);
  const [intensity, setIntensity] = useState<CrisisIntensity | null>(null);
  const [description, setDescription] = useState('');
  const [duration, setDuration] = useState('');
  const [period, setPeriod] = useState<'Manhã' | 'Tarde' | 'Noite'>('Manhã');

  // Inicialização com Data Local
  const [entryDate, setEntryDate] = useState(getLocalTodayString());

  const [history, setHistory] = useState<BehaviorEntry[]>([]);
  const [loading, setLoading] = useState(false);

  // Determinar o UID da criança alvo
  const targetUid = preSelectedChildId || (userProfile.manages && userProfile.manages.length > 0 ? userProfile.manages[0] : null);

  // Carregar histórico com filtros opcionais
  useEffect(() => {
    if (!targetUid) return;

    let query = db.collection('users').doc(targetUid).collection('behavior_entries');

    // 🆕 Lógica de Filtro de Datas
    if (startDate || endDate) {
        // Se houver filtro, ordena por dataString para permitir range queries simples sem índices complexos imediatos
        query = query.orderBy('dateString', 'desc');

        if (startDate) query = query.where('dateString', '>=', startDate);
        if (endDate) query = query.where('dateString', '<=', endDate);
    } else {
        // Comportamento padrão: últimos 20 por timestamp
        query = query.orderBy('timestamp', 'desc').limit(20);
    }

    const unsubscribe = query.onSnapshot(snapshot => {
        const entries = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as BehaviorEntry));
        // Filtrar alertas automáticos do sistema (Ex: Entrada na Sala de Calma)
        const filteredEntries = entries.filter(e => e.authorId !== 'SYSTEM');
        setHistory(filteredEntries);
      });

    return () => unsubscribe();
  }, [targetUid, startDate, endDate]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!targetUid || !selectedType) return;

    if (selectedType === 'CRISIS' && !intensity) {
      alert("Por favor, selecione a intensidade da crise.");
      return;
    }

    setLoading(true);
    try {
      const newEntry: Omit<BehaviorEntry, 'id'> = {
        userId: targetUid,
        authorId: userProfile.uid,
        timestamp: Date.now(),
        dateString: entryDate,
        type: selectedType,
        period,
        description,
        duration,
        ...(selectedType === 'CRISIS' && { intensity: intensity || undefined }),
      };

      await db.collection('users').doc(targetUid).collection('behavior_entries').add(newEntry);

      // Reset form
      setSelectedType(null);
      setIntensity(null);
      setDescription('');
      setDuration('');
    } catch (error) {
      console.error("Erro ao salvar:", error);
      alert("Erro ao salvar registro.");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (readOnly) return;
    if (!targetUid || !window.confirm("Apagar este registro?")) return;
    try {
      await db.collection('users').doc(targetUid).collection('behavior_entries').doc(id).delete();
    } catch (error) {
      console.error("Erro ao apagar:", error);
    }
  };

  if (!targetUid) {
    return <div className="p-4 text-center text-slate-500">Nenhuma criança vinculada ou selecionada.</div>;
  }

  return (
    <div className="space-y-6 animate-in fade-in">

      {/* SELEÇÃO DO TIPO DE EVENTO - OCULTO SE READONLY */}
      {!readOnly && (
        <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
                O que você observou?
            </h3>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
            {EVENT_TYPES.map((type) => (
                <button
                key={type.id}
                onClick={() => { setSelectedType(type.id); setIntensity(null); }}
                className={`p-3 rounded-xl border-2 flex flex-col items-center justify-center gap-2 transition-all ${
                    selectedType === type.id 
                    ? `${type.color} ring-2 ring-offset-2 ring-blue-100` 
                    : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'
                }`}
                >
                <div className="text-xl">{type.icon}</div>
                <span className="text-xs font-bold">{type.label}</span>
                </button>
            ))}
            </div>
        </div>
      )}

      {/* FORMULÁRIO DE DETALHES - OCULTO SE READONLY */}
      {!readOnly && selectedType && (
        <form onSubmit={handleSubmit} className="bg-white p-5 rounded-xl border border-blue-200 shadow-md animate-in slide-in-from-top-2">
           <div className="flex items-center justify-between mb-4 pb-2 border-b border-slate-100">
              <h3 className="font-bold text-blue-800 flex items-center gap-2">
                  {EVENT_TYPES.find(t => t.id === selectedType)?.icon}
                  Detalhes: {EVENT_TYPES.find(t => t.id === selectedType)?.label}
              </h3>
              <button type="button" onClick={() => setSelectedType(null)} className="text-xs text-slate-400 underline">Cancelar</button>
           </div>

           <div className="space-y-4">
              <div className="flex gap-3">
                 <div className="flex-1">
                    <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Data</label>
                    <input 
                        type="date" 
                        value={entryDate} 
                        onChange={e => setEntryDate(e.target.value)}
                        className="w-full p-2 border border-slate-200 rounded-lg text-sm"
                    />
                 </div>
                 <div className="flex-1">
                    <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Período</label>
                    <select 
                        value={period} 
                        onChange={e => setPeriod(e.target.value as any)}
                        className="w-full p-2 border border-slate-200 rounded-lg text-sm"
                    >
                        <option value="Manhã">Manhã</option>
                        <option value="Tarde">Tarde</option>
                        <option value="Noite">Noite</option>
                    </select>
                 </div>
              </div>

              {selectedType === 'CRISIS' && (
                  <div>
                      <label className="text-xs font-bold text-slate-500 uppercase block mb-2">Intensidade da Crise</label>
                      <div className="flex gap-2">
                          {INTENSITIES.map(lvl => (
                              <button
                                key={lvl.id}
                                type="button"
                                onClick={() => setIntensity(lvl.id)}
                                className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all border ${
                                    intensity === lvl.id 
                                    ? lvl.color + ' border-transparent ring-2 ring-offset-1 ring-slate-200'
                                    : 'bg-white text-slate-500 border-slate-200'
                                }`}
                              >
                                {lvl.label}
                              </button>
                          ))}
                      </div>
                  </div>
              )}

              <div>
                  <label className="text-xs font-bold text-slate-500 uppercase block mb-1">O que aconteceu? (Observações)</label>
                  <textarea 
                      value={description}
                      onChange={e => setDescription(e.target.value)}
                      placeholder="Descreva gatilhos, contexto ou alimentos..."
                      className="w-full p-3 border border-slate-200 rounded-lg text-sm h-24 resize-none"
                  />
              </div>

              <div>
                  <label className="text-xs font-bold text-slate-500 uppercase block mb-1">Duração (Opcional)</label>
                  <div className="relative">
                      <Clock className="w-4 h-4 absolute left-3 top-2.5 text-slate-400" />
                      <input 
                          type="text" 
                          value={duration} 
                          onChange={e => setDuration(e.target.value)}
                          placeholder="Ex: 20 min"
                          className="w-full pl-9 p-2 border border-slate-200 rounded-lg text-sm"
                      />
                  </div>
              </div>

              <button 
                type="submit" 
                disabled={loading}
                className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 transition flex items-center justify-center gap-2"
              >
                  <Save className="w-4 h-4" />
                  {loading ? 'Salvando...' : 'Registrar Evento'}
              </button>
           </div>
        </form>
      )}

      {/* HISTÓRICO RECENTE */}
      <div className={readOnly ? "" : "mt-8"}>
          <div className="flex justify-between items-center mb-3">
            <h3 className="font-bold text-slate-700 flex items-center gap-2">
                <Calendar className="w-4 h-4" /> Histórico {startDate || endDate ? '(Filtrado)' : 'Recente'}
            </h3>
          </div>

          <div className="space-y-3">
              {history.length === 0 ? (
                  <p className="text-center text-slate-400 text-sm py-4">Nenhum registro comportamental encontrado.</p>
              ) : (
                  history.map(entry => {
                      const typeInfo = EVENT_TYPES.find(t => t.id === entry.type);
                      return (
                          <div key={entry.id} className="bg-white p-3 rounded-xl border-l-4 shadow-sm border-slate-100 flex gap-3 relative" style={{ borderLeftColor: typeInfo?.color.includes('red') ? '#ef4444' : '#cbd5e1' }}>
                              <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${typeInfo?.color.split(' ')[0]} ${typeInfo?.color.split(' ')[1]}`}>
                                  {typeInfo?.icon}
                              </div>
                              <div className="flex-1 min-w-0">
                                  <div className="flex justify-between items-start">
                                      <p className="font-bold text-slate-800 text-sm">{typeInfo?.label}</p>
                                      <span className="text-[10px] text-slate-400">
                                          {new Date(entry.dateString).toLocaleDateString('pt-BR')} • {entry.period}
                                      </span>
                                  </div>

                                  {entry.intensity && (
                                      <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold uppercase mb-1 ${INTENSITIES.find(i => i.id === entry.intensity)?.color}`}>
                                          {entry.intensity}
                                      </span>
                                  )}

                                  {entry.description && (
                                      <p className="text-xs text-slate-600 mt-1 line-clamp-2">"{entry.description}"</p>
                                  )}

                                  {entry.duration && (
                                      <p className="text-[10px] text-slate-500 mt-1 flex items-center gap-1">
                                          <Clock className="w-3 h-3" /> {entry.duration}
                                      </p>
                                  )}
                              </div>
                              {!readOnly && (
                                <button onClick={() => handleDelete(entry.id)} className="absolute bottom-2 right-2 text-slate-300 hover:text-red-500">
                                    <Trash2 className="w-4 h-4" />
                                </button>
                              )}
                          </div>
                      );
                  })
              )}
          </div>
      </div>
    </div>
  );
};

export default BehaviorDiary;

import React, { useState, useEffect } from 'react';
import firebase, { auth, db } from './services/firebase';
import { ProfileType, MoodType } from './types';
import { Loader2, ArrowLeft, User, ShieldCheck, CheckCircle2, Stethoscope, GraduationCap, Mail, RefreshCw, Send, LogIn, FileText } from 'lucide-react';
import RobotMascot from './components/RobotMascot';

interface AuthProps {
  onLoginSuccess: () => void;
}

type AuthView = 'LOGIN' | 'PROFILE_SELECT' | 'REGISTER' | 'VERIFY_EMAIL';

// Paleta de Cores Pastel
const pastel = {
  blue: "#A9CCE3", // Principal (Criança/Login)
  yellow: "#F9E79F", // Secundário (Adulto)
  pink: "#F1948A", // Destaque/Atenção (Links/Erros)
  green: "#A3E4D7", // Responsável/Highlight
  teal: "#76D7C4",   // Profissional
  purple: "#D7BDE2" // Escola
};

const HEALTH_COUNCILS = ['CRM', 'CRP', 'CREFITO', 'CRF', 'COREN', 'Outros'];

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [view, setView] = useState<AuthView>('LOGIN');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  // Professional State
  const [professionalCouncil, setProfessionalCouncil] = useState('CRM');
  const [professionalCode, setProfessionalCode] = useState('');

  // School State
  const [cnpj, setCnpj] = useState('');

  // Guardian State
  const [guardianName, setGuardianName] = useState('');
  const [guardianPin, setGuardianPin] = useState('');

  // Child Specific
  const [childUsername, setChildUsername] = useState('');
  const [childPassword, setChildPassword] = useState('');

  const [selectedProfile, setSelectedProfile] = useState<ProfileType | null>(null);

  // Estado para armazenar credenciais temporárias durante a verificação
  const [pendingCreds, setPendingCreds] = useState<{email: string, password: string} | null>(null);

  // Verificar estado inicial se já existe usuário mas não verificado
  useEffect(() => {
      if (auth.currentUser && !auth.currentUser.emailVerified) {
          // Se for criança (dominio mock), ignora a verificação
          if (!auth.currentUser.email?.endsWith('@child.eab.app')) {
              setEmail(auth.currentUser.email || '');
              setView('VERIFY_EMAIL');
          }
      }
  }, []);

  // Polling automático para verificar e-mail
  useEffect(() => {
    let interval: any;
    if (view === 'VERIFY_EMAIL') {
        const checkStatus = async () => {
            if (auth.currentUser) {
                try {
                    await auth.currentUser.reload();
                    if (auth.currentUser.emailVerified) {
                        clearInterval(interval);
                        await auth.signOut();
                        setSuccessMessage("E-mail verificado com sucesso! Faça login para começar.");
                        setView('LOGIN');
                        setPendingCreds(null);
                    }
                } catch (e) {
                    console.error("Erro ao verificar status:", e);
                }
            } else if (pendingCreds) {
                 // Tenta relogar silenciosamente para checar status se sessão caiu
                 try {
                    const cred = await auth.signInWithEmailAndPassword(pendingCreds.email, pendingCreds.password);
                    if (cred.user?.emailVerified) {
                        clearInterval(interval);
                        await auth.signOut();
                        setSuccessMessage("E-mail verificado com sucesso! Faça login para começar.");
                        setView('LOGIN');
                        setPendingCreds(null);
                    }
                 } catch (e) {
                     // Ignora erros de login silencioso
                 }
            }
        };

        // Verifica a cada 3 segundos
        interval = setInterval(checkStatus, 3000);
    }
    return () => clearInterval(interval);
  }, [view, pendingCreds]);

  const handleProfileSelect = (type: ProfileType) => {
    setSelectedProfile(type);
    setView('REGISTER');
    setError(null);
    setSuccessMessage(null);

    setName('');
    setPassword('');
    setEmail('');
    setProfessionalCouncil('CRM');
    setProfessionalCode('');
    setCnpj('');
    setGuardianName('');
    setGuardianPin('');
    setChildUsername('');
    setChildPassword('');
  };

  const executeRegistration = async () => {
      setLoading(true);
      setError(null);

      // Re-sanitize inputs
      const cleanEmail = email.trim();
      const cleanPassword = password;
      const cleanGuardianPin = guardianPin.trim();
      const cleanChildUsername = childUsername.trim().toLowerCase().replace(/\s+/g, '');

      try {
        if (selectedProfile === ProfileType.CHILD) {
            // 1. Cria o Responsável (Este receberá o e-mail de verificação)
            const guardianCredential = await auth.createUserWithEmailAndPassword(cleanEmail, cleanGuardianPin);
            const guardianUser = guardianCredential.user;

            if (guardianUser) {
                await guardianUser.updateProfile({ displayName: guardianName.trim() });
                // ENVIA O E-MAIL DE VERIFICAÇÃO NATIVO DO FIREBASE
                await guardianUser.sendEmailVerification();
            }

            const guardianData = {
              uid: guardianUser?.uid,
              email: guardianUser?.email,
              displayName: guardianName.trim(),
              profileType: ProfileType.ADULT,
              manages: [],
              createdAt: Date.now(),
            };
            if (guardianUser) await db.collection("users").doc(guardianUser.uid).set(guardianData);

            // 2. Cria a Criança (Sem verificação de email pois é fake)
            const childFullEmail = `${cleanChildUsername}@child.eab.app`;
            // Pequeno delay para garantir ordem no backend se necessário
            await new Promise(r => setTimeout(r, 500));

            const childCredential = await auth.createUserWithEmailAndPassword(childFullEmail, childPassword);
            const childUser = childCredential.user;
            if (childUser) await childUser.updateProfile({ displayName: name.trim() });

            const childData = {
              uid: childUser?.uid,
              email: childFullEmail,
              displayName: name.trim(),
              childUsername: cleanChildUsername,
              profileType: ProfileType.CHILD,
              linkedGuardianId: guardianUser?.uid,
              childPassword: childPassword,
              createdAt: Date.now(),
            };
            if (childUser) await db.collection("users").doc(childUser.uid).set(childData);

            // 3. Vincula e prepara verificação
            // Logar como pai para verificação
            await auth.signInWithEmailAndPassword(cleanEmail, cleanGuardianPin);
            if (guardianUser) {
                await db.collection("users").doc(guardianUser.uid).update({
                    manages: firebase.firestore.FieldValue.arrayUnion(childUser?.uid),
                });
            }

            setPendingCreds({ email: cleanEmail, password: cleanGuardianPin });
            setView('VERIFY_EMAIL');

        } else {
            // Adulto, Profissional ou Escola
            const userCredential = await auth.createUserWithEmailAndPassword(cleanEmail, cleanPassword);
            const user = userCredential.user;

            if (user) {
                await user.updateProfile({ displayName: name.trim() });
                // ENVIA O E-MAIL DE VERIFICAÇÃO NATIVO DO FIREBASE
                await user.sendEmailVerification();
            }

            let profileTypeToSave = null; 
            if (selectedProfile === ProfileType.PROFESSIONAL) profileTypeToSave = ProfileType.PROFESSIONAL;
            if (selectedProfile === ProfileType.SCHOOL) profileTypeToSave = ProfileType.SCHOOL;

            const userData: any = {
              uid: user?.uid,
              email: user?.email,
              displayName: name.trim(),
              profileType: profileTypeToSave, 
              createdAt: Date.now(),
            };

            if (selectedProfile === ProfileType.PROFESSIONAL) {
                userData.professionalCouncil = professionalCouncil;
                userData.professionalCode = professionalCode;
                userData.professionalId = `${professionalCouncil} ${professionalCode}`;
            }

            if (selectedProfile === ProfileType.SCHOOL) {
                userData.cnpj = cnpj.replace(/[^\d]+/g, ''); 
            }

            if (user) await db.collection("users").doc(user.uid).set(userData);

            // Mantém logado para a tela de verificação
            setPendingCreds({ email: cleanEmail, password: cleanPassword });
            setView('VERIFY_EMAIL');
        }
      } catch (err: any) {
          console.error(err);
          let msg = "Erro ao criar conta.";
          if (err.code === 'auth/email-already-in-use') msg = "Este e-mail já está em uso.";
          if (err.code === 'auth/weak-password') msg = "A senha é muito fraca.";
          setError(msg);
      } finally {
          setLoading(false);
      }
  };

  const resendVerification = async () => {
      if (auth.currentUser) {
          try {
              await auth.currentUser.sendEmailVerification();
              setSuccessMessage("Novo e-mail de verificação enviado!");
          } catch (e) {
              setError("Aguarde alguns minutos antes de reenviar.");
          }
      }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);

    const cleanEmail = email.trim(); 
    const cleanPassword = password; 
    const cleanGuardianPin = guardianPin.trim();
    const cleanChildUsername = childUsername.trim().toLowerCase().replace(/\s+/g, ''); 

    try {
      if (view === 'REGISTER') {
        if (!selectedProfile) throw new Error("Erro: Perfil não selecionado.");

        if (selectedProfile === ProfileType.CHILD) {
          if (!cleanEmail || !guardianName.trim() || !cleanGuardianPin)
            throw new Error("Preencha os dados do Responsável.");
          if (!name.trim() || !cleanChildUsername || !childPassword)
            throw new Error("Preencha os dados da Criança.");
          if (cleanGuardianPin.length < 6)
            throw new Error("A senha do responsável deve ter no mínimo 6 caracteres.");
          if (childPassword.length < 6)
            throw new Error("A senha da criança deve ter no mínimo 6 caracteres.");
          if (/[^a-z0-9._-]/.test(cleanChildUsername)) {
             throw new Error("O usuário da criança deve conter apenas letras minúsculas, números, ponto ou traço.");
          }
        } else {
          if (!name.trim() || !cleanEmail || !cleanPassword)
            throw new Error("Preencha todos os campos.");
          if (selectedProfile === ProfileType.PROFESSIONAL && !professionalCode) {
             throw new Error("Por favor, preencha o número de registro profissional.");
          }
          if (selectedProfile === ProfileType.SCHOOL && !cnpj) {
             throw new Error("Por favor, preencha o CNPJ da escola.");
          }
        }

        // INICIA O PROCESSO DE REGISTRO E VERIFICAÇÃO
        await executeRegistration();
        return;
      } 

      // --- LOGIN FLOW ---
      let loginIdentifier = cleanEmail;
      let isChildLogin = false;
      if (!loginIdentifier.includes('@')) {
        loginIdentifier = `${loginIdentifier.toLowerCase().replace(/\s+/g, '')}@child.eab.app`;
        isChildLogin = true;
      } else if (loginIdentifier.endsWith('@child.eab.app')) {
        isChildLogin = true;
      }

      const cred = await auth.signInWithEmailAndPassword(loginIdentifier, cleanPassword);

      // --- CHECK EMAIL VERIFICATION ---
      // Se não for criança (que tem email fake), EXIGE verificação
      if (cred.user && !cred.user.emailVerified && !isChildLogin) {
          setPendingCreds({ email: loginIdentifier, password: cleanPassword });
          setView('VERIFY_EMAIL');
      } else {
          onLoginSuccess();
      }

    } catch (err: any) {
      console.error(err);
      let msg = "Erro ao processar.";
      if (err.message) msg = err.message;
      if (err.code === 'auth/weak-password') msg = "A senha deve ter pelo menos 6 caracteres.";
      if (err.code === 'auth/invalid-email') msg = "O formato do e-mail é inválido.";
      if (err.code === 'auth/email-already-in-use') {
        if (view === 'REGISTER' && selectedProfile === ProfileType.CHILD && !guardianName)
          msg = "Este e-mail de responsável já está cadastrado.";
        else if (view === 'REGISTER' && selectedProfile === ProfileType.CHILD)
          msg = "Este nome de usuário para a criança já existe. Tente outro.";
        else msg = "Este e-mail já está cadastrado. Tente fazer login.";
      }
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' || err.code === 'auth/invalid-login-credentials') {
        msg = "Dados de acesso incorretos. Verifique e-mail/usuário e senha.";
      }
      setError(msg);
    } finally {
      if (view !== 'VERIFY_EMAIL') setLoading(false);
    }
  };

  const getThemeColor = () => {
      if (view === 'REGISTER' || view === 'VERIFY_EMAIL') {
          if (selectedProfile === ProfileType.CHILD) return pastel.blue;
          if (selectedProfile === ProfileType.PROFESSIONAL) return pastel.teal;
          if (selectedProfile === ProfileType.SCHOOL) return pastel.purple;
          return pastel.yellow;
      }
      return pastel.yellow;
  };

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center p-4 font-sans"
      style={{
        background: `linear-gradient(135deg, ${pastel.blue} 0%, ${pastel.yellow} 25%, ${pastel.green} 60%, ${pastel.purple} 100%)`,
      }}
    >
      <div
        className="w-full max-w-2xl rounded-3xl p-6 shadow-3xl transition-all duration-300 hover:shadow-4xl bg-white/95 backdrop-blur-sm relative overflow-hidden border-[6px] border-slate-100"
        style={{
          boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.4)',
          borderColor: getThemeColor(),
        }}
      >
        <div className="flex flex-col items-center mb-6">
          <div className="transform scale-75 mb-[-10px]">
            <RobotMascot mood={MoodType.HAPPY} />
          </div>
          <h1 className="text-3xl font-black tracking-wide mb-1 text-slate-900" style={{ color: pastel.blue }}>EAB</h1>
          <p className="text-slate-800 font-medium text-center text-sm">
            {view === 'PROFILE_SELECT' ? 'Quem vai usar o aplicativo?' : view === 'VERIFY_EMAIL' ? 'Confirmação de E-mail' : 'Bem-vindo(a), vamos começar o dia!'}
          </p>
        </div>

        {successMessage && (
          <div className="mb-4 text-center text-sm p-3 rounded-xl border-2 animate-in fade-in slide-in-from-top-1 shadow-lg flex items-center justify-center gap-2" style={{ color: '#155724', backgroundColor: '#D4EDDA', borderColor: '#C3E6CB' }}>
            <CheckCircle2 size={16} /> <span className="font-bold">{successMessage}</span>
          </div>
        )}

        {error && (
          <div className="mb-4 text-center text-sm bg-red-100 p-3 rounded-xl border-2 animate-in fade-in slide-in-from-top-1 shadow-lg" style={{ color: '#C0392B', borderColor: pastel.pink }}>
            {error}
          </div>
        )}

        {/* PROFILE SELECT */}
        {view === 'PROFILE_SELECT' && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 w-full">
            <fieldset className="rounded-3xl p-6 pt-4 relative border-4 shadow-xl bg-white/50 backdrop-blur-sm" style={{ border: `3px solid ${pastel.blue}` }}>
              <legend className="text-lg font-black px-4 text-slate-800 uppercase tracking-widest bg-white rounded-full border-2 border-blue-200 shadow-sm" style={{ color: pastel.blue }}>Tipo de Perfil</legend>
              <div className="grid grid-cols-2 gap-3 mt-4">
                <button type="button" onClick={() => handleProfileSelect(ProfileType.CHILD)} className="flex flex-col items-center justify-center p-3 rounded-2xl bg-white border-b-[4px] border-r-[4px] border-blue-200 shadow-lg hover:shadow-xl hover:border-blue-300 active:border-0 active:translate-y-1 active:translate-x-1 active:shadow-inner transition-all duration-200 h-32 group">
                  <div className="w-12 h-12 mb-2 flex items-center justify-center rounded-full bg-gradient-to-br from-cyan-300 to-blue-500 shadow-md transform group-hover:scale-110 transition-transform duration-300 border-2 border-white ring-2 ring-blue-50"><span className="text-2xl filter drop-shadow-sm">🧸</span></div>
                  <span className="font-black text-xs text-slate-700 uppercase tracking-wide group-hover:text-blue-600 transition-colors">Criança</span>
                </button>
                <button type="button" onClick={() => handleProfileSelect(ProfileType.ADULT)} className="flex flex-col items-center justify-center p-3 rounded-2xl bg-white border-b-[4px] border-r-[4px] border-yellow-200 shadow-lg hover:shadow-xl hover:border-yellow-300 active:border-0 active:translate-y-1 active:translate-x-1 active:shadow-inner transition-all duration-200 h-32 group">
                  <div className="w-12 h-12 mb-2 flex items-center justify-center rounded-full bg-gradient-to-br from-yellow-300 to-orange-400 shadow-md transform group-hover:scale-110 transition-transform duration-300 border-2 border-white ring-2 ring-yellow-50"><span className="text-2xl filter drop-shadow-sm">👤</span></div>
                  <span className="font-black text-xs text-slate-700 uppercase tracking-wide group-hover:text-yellow-600 transition-colors">Adulto</span>
                </button>
                <button type="button" onClick={() => handleProfileSelect(ProfileType.PROFESSIONAL)} className="flex flex-col items-center justify-center p-3 rounded-2xl bg-white border-b-[4px] border-r-[4px] border-teal-200 shadow-lg hover:shadow-xl hover:border-teal-300 active:border-0 active:translate-y-1 active:translate-x-1 active:shadow-inner transition-all duration-200 h-32 group">
                  <div className="w-12 h-12 mb-2 flex items-center justify-center rounded-full bg-gradient-to-br from-teal-300 to-green-400 shadow-md transform group-hover:scale-110 transition-transform duration-300 border-2 border-white ring-2 ring-teal-50"><Stethoscope className="w-6 h-6 text-white drop-shadow-sm" /></div>
                  <span className="font-black text-xs text-slate-700 uppercase tracking-wide group-hover:text-teal-600 transition-colors text-center leading-tight">Profissional</span>
                </button>
                <button type="button" onClick={() => handleProfileSelect(ProfileType.SCHOOL)} className="flex flex-col items-center justify-center p-3 rounded-2xl bg-white border-b-[4px] border-r-[4px] border-purple-200 shadow-lg hover:shadow-xl hover:border-purple-300 active:border-0 active:translate-y-1 active:translate-x-1 active:shadow-inner transition-all duration-200 h-32 group">
                  <div className="w-12 h-12 mb-2 flex items-center justify-center rounded-full bg-gradient-to-br from-purple-300 to-indigo-400 shadow-md transform group-hover:scale-110 transition-transform duration-300 border-2 border-white ring-2 ring-purple-50"><GraduationCap className="w-6 h-6 text-white drop-shadow-sm" /></div>
                  <span className="font-black text-xs text-slate-700 uppercase tracking-wide group-hover:text-purple-600 transition-colors text-center leading-tight">Escola</span>
                </button>
              </div>
            </fieldset>
            <button onClick={() => setView('LOGIN')} className="w-full mt-4 flex items-center justify-center gap-2 font-bold py-3 text-slate-900 hover:text-slate-900 transition-colors" style={{ color: pastel.pink }}><ArrowLeft className="w-5 h-5" /> Voltar ao Login</button>
          </div>
        )}

        {/* VERIFY EMAIL LINK VIEW */}
        {view === 'VERIFY_EMAIL' && (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 w-full text-center">
                <div className="bg-blue-50 p-6 rounded-2xl border-2 border-blue-200">
                    <Mail className="w-16 h-16 mx-auto text-blue-500 mb-4 animate-bounce" />
                    <h3 className="font-bold text-slate-800 text-xl mb-2">Verifique seu E-mail</h3>
                    <p className="text-sm text-slate-600 leading-relaxed">
                        Enviamos um <strong>link de confirmação</strong> para:
                        <br/>
                        <span className="font-bold text-blue-700 block mt-1 text-base">{email}</span>
                    </p>
                    <p className="text-xs text-slate-500 mt-4 italic">
                        Clique no link enviado para ativar sua conta.<br/>
                        Aguarde, a verificação será detectada automaticamente...
                    </p>
                    <div className="mt-4 flex justify-center">
                        <Loader2 className="animate-spin text-blue-600 w-6 h-6" />
                    </div>
                </div>

                <div className="space-y-3">
                    <button
                        onClick={resendVerification}
                        className="w-full text-blue-600 font-bold py-3 rounded-xl border-2 border-blue-100 hover:bg-blue-50 flex items-center justify-center transition-all"
                    >
                        <Send className="w-4 h-4 mr-2" /> Reenviar E-mail
                    </button>
                </div>

                <button
                    onClick={() => { setView('LOGIN'); auth.signOut(); }}
                    className="mt-4 text-sm font-bold text-slate-400 hover:text-slate-600 transition-colors flex items-center justify-center gap-1 mx-auto"
                >
                    <LogIn className="w-3 h-3"/> Voltar para Login
                </button>
            </div>
        )}

        {/* REGISTER OR LOGIN FORM */}
        {(view === 'LOGIN' || view === 'REGISTER') && (
          <form onSubmit={handleAuth} className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
            {view === 'REGISTER' ? (
              <>
                <div className="flex items-center gap-3 p-3 rounded-xl border-2 mb-2 shadow-xl" style={{ backgroundColor: getThemeColor() + "60", borderColor: getThemeColor() }}>
                  <span className="text-2xl">{selectedProfile === ProfileType.CHILD ? '🧸' : selectedProfile === ProfileType.PROFESSIONAL ? <Stethoscope className="w-6 h-6"/> : selectedProfile === ProfileType.SCHOOL ? <GraduationCap className="w-6 h-6"/> : '👤'}</span>
                  <div className="flex-1">
                    <p className="text-xs font-bold uppercase text-slate-700">Criando conta para</p>
                    <p className="font-extrabold text-lg" style={{ color: selectedProfile === ProfileType.CHILD ? pastel.blue : selectedProfile === ProfileType.PROFESSIONAL ? '#0f766e' : selectedProfile === ProfileType.SCHOOL ? '#7e22ce' : '#ca8a04' }}>
                      {selectedProfile === ProfileType.CHILD ? 'Criança' : selectedProfile === ProfileType.PROFESSIONAL ? 'Profissional' : selectedProfile === ProfileType.SCHOOL ? 'Escola' : 'Adulto'}
                    </p>
                  </div>
                  <button type="button" onClick={() => setView('PROFILE_SELECT')} className="text-sm font-extrabold underline hover:no-underline transition-colors text-slate-900" style={{ color: pastel.pink }}>Alterar</button>
                </div>

                {selectedProfile === ProfileType.CHILD ? (
                  <div className="space-y-4">
                    <div>
                      <label className="block text-sm font-bold mb-1 text-slate-800">E-mail do Responsável (Login)</label>
                      <input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="exemplo@email.com" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: pastel.blue, backgroundColor: "#FFFFFF" }} />
                    </div>
                    <div className="rounded-xl p-4 shadow-xl border-2" style={{ backgroundColor: pastel.green + "40", borderColor: pastel.green }}>
                      <div className="flex items-center gap-2 mb-3 text-slate-900" style={{ color: pastel.green }}><ShieldCheck className="w-5 h-5" /><span className="text-sm font-extrabold uppercase tracking-wide">Dados do Responsável</span></div>
                      <div className="space-y-3">
                        <div><label className="block text-xs font-bold mb-1 text-slate-800">Nome do Responsável</label><input type="text" value={guardianName} onChange={(e) => setGuardianName(e.target.value)} placeholder="Ex: Maria Silva" className="w-full px-3 py-2 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 text-sm shadow-md" style={{ borderColor: pastel.green }} /></div>
                        <div><label className="block text-xs font-bold mb-1 text-slate-800">Senha do Responsável</label><input type="password" value={guardianPin} onChange={(e) => setGuardianPin(e.target.value)} placeholder="••••••" className="w-full px-3 py-2 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 text-sm font-mono shadow-md" style={{ borderColor: pastel.green }} /></div>
                      </div>
                    </div>
                    <div className="rounded-xl p-4 shadow-2xl border-2" style={{ backgroundColor: pastel.blue + "40", borderColor: pastel.blue }}>
                      <div className="flex items-center gap-2 mb-3 text-slate-900" style={{ color: pastel.blue }}><User className="w-5 h-5" /><span className="text-sm font-extrabold uppercase tracking-wide">Dados da Criança</span></div>
                      <div className="space-y-3">
                        <div><label className="block text-xs font-bold mb-1 text-slate-800">Nome Completo</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} placeholder="Ex: Pedro Souza" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-md" style={{ borderColor: pastel.blue }} /></div>
                        <div><label className="block text-xs font-bold mb-1 text-slate-900" style={{ color: pastel.blue }}>Nome de Usuário (Login)</label><input type="text" value={childUsername} onChange={(e) => setChildUsername(e.target.value)} placeholder="pedrinho123" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 placeholder-slate-500 bg-white shadow-md" style={{ borderColor: pastel.blue }} /><p className="text-[10px] mt-1 text-slate-700 font-medium">Sem espaços. A criança usará este nome para entrar.</p></div>
                        <div><label className="block text-xs font-bold mb-1 text-slate-800">Senha/PIN da Criança</label><input type="password" value={childPassword} onChange={(e) => setChildPassword(e.target.value)} placeholder="••••••" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 placeholder-slate-500 font-mono text-lg shadow-md" style={{ borderColor: pastel.blue }} /></div>
                      </div>
                    </div>
                  </div>
                ) : (
                  <>
                    <div><label className="block text-sm font-bold mb-1 text-slate-800">{selectedProfile === ProfileType.PROFESSIONAL ? 'Nome Completo (Profissional)' : selectedProfile === ProfileType.SCHOOL ? 'Nome da Escola' : 'Nome de Usuário'}</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} placeholder={selectedProfile === ProfileType.SCHOOL ? "Ex: Escola Caminho do Saber" : "Ex: Dr. João Silva"} className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: getThemeColor() }} /></div>
                    {selectedProfile === ProfileType.PROFESSIONAL && (
                        <div className="flex gap-2">
                            <div className="w-1/3"><label className="block text-sm font-bold mb-1 text-slate-800">Conselho</label><div className="relative"><select value={professionalCouncil} onChange={(e) => setProfessionalCouncil(e.target.value)} className="w-full px-2 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 bg-white appearance-none shadow-lg" style={{ borderColor: getThemeColor() }}>{HEALTH_COUNCILS.map(c => <option key={c} value={c}>{c}</option>)}</select></div></div>
                            <div className="w-2/3"><label className="block text-sm font-bold mb-1 text-slate-800">Nº Registro</label><input type="text" value={professionalCode} onChange={(e) => setProfessionalCode(e.target.value)} placeholder="Ex: 123456" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: getThemeColor() }} /></div>
                        </div>
                    )}
                    {selectedProfile === ProfileType.SCHOOL && (<div><label className="block text-sm font-bold mb-1 text-slate-800">CNPJ</label><input type="text" value={cnpj} onChange={(e) => setCnpj(e.target.value)} placeholder="00.000.000/0000-00" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: getThemeColor() }} /></div>)}
                    <div><label className="block text-sm font-bold mb-1 text-slate-800">E-mail</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="email@exemplo.com" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: getThemeColor() }} /></div>
                    <div><label className="block text-sm font-bold mb-1 text-slate-800">Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:ring-4 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 font-mono text-lg shadow-lg" style={{ borderColor: getThemeColor() }} /></div>
                  </>
                )}
              </>
            ) : (
              <>
                <div><label className="block text-sm font-bold mb-1 text-slate-800">E-mail ou Usuário</label><input type="text" value={email} onChange={(e) => setEmail(e.target.value)} placeholder="email@exemplo.com ou usuario" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:border-blue-700 focus:ring-4 focus:ring-blue-300 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 shadow-lg" style={{ borderColor: pastel.blue }} /></div>
                <div><label className="block text-sm font-bold mb-1 text-slate-800">Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••" className="w-full px-4 py-3 border-2 rounded-lg focus:outline-none focus:border-blue-700 focus:ring-4 focus:ring-blue-300 focus:ring-opacity-70 text-slate-900 placeholder-slate-500 font-mono text-lg shadow-lg" style={{ borderColor: pastel.blue }} /></div>
              </>
            )}

            <button type="submit" disabled={loading} className="w-full text-white font-extrabold py-3.5 rounded-xl shadow-2xl hover:shadow-3xl mt-4 flex items-center justify-center transition-all duration-300 transform hover:scale-[1.02]" style={{ backgroundColor: view === 'LOGIN' ? pastel.blue : getThemeColor(), boxShadow: `0 10px 15px -3px ${view === 'LOGIN' ? pastel.blue : getThemeColor()}80, 0 4px 6px -2px ${view === 'LOGIN' ? pastel.blue : getThemeColor()}40` }}>{loading ? (<Loader2 className="animate-spin w-6 h-6" />) : view === 'REGISTER' ? ('CADASTRAR E VERIFICAR') : ('ENTRAR')}</button>

            <div className="mt-4 text-center">
              {view === 'LOGIN' ? (<button type="button" onClick={() => setView('PROFILE_SELECT')} className="text-sm font-extrabold hover:underline transition-colors text-slate-900" style={{ color: pastel.pink }}>NÃO TEM CONTA? CRIE AGORA</button>) : (<button type="button" onClick={() => setView('LOGIN')} className="text-sm font-extrabold hover:underline transition-colors text-slate-900" style={{ color: pastel.pink }}>JÁ TEM UMA CONTA? FAÇA LOGIN</button>)}
              <div className="mt-6 border-t border-slate-200/50 pt-4 text-center space-y-2">
                  <a href="/documentation.html" target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-2 text-xs font-bold text-slate-600 hover:text-blue-600 transition-colors bg-white/50 hover:bg-white px-3 py-1.5 rounded-full shadow-sm border border-slate-100">
                      <FileText className="w-3 h-3" /> Ver Apresentação do Projeto
                  </a>
                  <p className="text-slate-800 font-medium text-center text-xs opacity-70">
                      Desenvolvido por MichelBB
                  </p>
              </div>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import firebase, { auth, db } from './services/firebase';
import { ProfileType, MoodType } from './types';
import { Loader2, ArrowLeft, User, ShieldCheck, CheckCircle2, Stethoscope, GraduationCap, Mail, RefreshCw, Send, LogIn, FileText } from 'lucide-react';
import RobotMascot from './components/RobotMascot';
import LandingPage from './components/LandingPage';

interface AuthProps {
  onLoginSuccess: () => void;
}

type AuthView = 'LOGIN' | 'PROFILE_SELECT' | 'REGISTER' | 'VERIFY_EMAIL';

// Paleta de Cores Pastel
const pastel = {
  blue: "#A9CCE3", // Principal (Criança/Login)
  yellow: "#F9E79F", // Secundário (Adulto)
  pink: "#F1948A", // Destaque/Atenção (Links/Erros)
  green: "#A3E4D7", // Responsável/Highlight
  teal: "#76D7C4",   // Profissional
  purple: "#D7BDE2" // Escola
};

const HEALTH_COUNCILS = ['CRM', 'CRP', 'CREFITO', 'CRF', 'COREN', 'Outros'];

const Auth: React.FC<AuthProps> = ({ onLoginSuccess }) => {
  const [view, setView] = useState<AuthView>('LOGIN');
  const [showLanding, setShowLanding] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  // Professional State
  const [professionalCouncil, setProfessionalCouncil] = useState('CRM');
  const [professionalCode, setProfessionalCode] = useState('');

  // School State
  const [cnpj, setCnpj] = useState('');

  // Guardian State
  const [guardianName, setGuardianName] = useState('');
  const [guardianPin, setGuardianPin] = useState('');

  // Child Specific
  const [childUsername, setChildUsername] = useState('');
  const [childPassword, setChildPassword] = useState('');

  const [selectedProfile, setSelectedProfile] = useState<ProfileType | null>(null);

  // Estado para armazenar credenciais temporárias durante a verificação
  const [pendingCreds, setPendingCreds] = useState<{email: string, password: string} | null>(null);

  // Verificar estado inicial se já existe usuário mas não verificado
  useEffect(() => {
      if (auth.currentUser && !auth.currentUser.emailVerified) {
          // Se for criança (dominio mock), ignora a verificação
          if (!auth.currentUser.email?.endsWith('@child.eab.app')) {
              setEmail(auth.currentUser.email || '');
              setView('VERIFY_EMAIL');
          }
      }
  }, []);

  // Polling automático para verificar e-mail
  useEffect(() => {
    let interval: any;
    if (view === 'VERIFY_EMAIL') {
        const checkStatus = async () => {
            if (auth.currentUser) {
                try {
                    await auth.currentUser.reload();
                    if (auth.currentUser.emailVerified) {
                        clearInterval(interval);
                        await auth.signOut();
                        setSuccessMessage("E-mail verificado com sucesso! Faça login para começar.");
                        setView('LOGIN');
                        setPendingCreds(null);
                    }
                } catch (e) {
                    console.error("Erro ao verificar status:", e);
                }
            } else if (pendingCreds) {
                 // Tenta relogar silenciosamente para checar status se sessão caiu
                 try {
                    const cred = await auth.signInWithEmailAndPassword(pendingCreds.email, pendingCreds.password);
                    if (cred.user?.emailVerified) {
                        clearInterval(interval);
                        await auth.signOut();
                        setSuccessMessage("E-mail verificado com sucesso! Faça login para começar.");
                        setView('LOGIN');
                        setPendingCreds(null);
                    }
                 } catch (e) {
                     // Ignora erros de login silencioso
                 }
            }
        };

        // Verifica a cada 3 segundos
        interval = setInterval(checkStatus, 3000);
    }
    return () => clearInterval(interval);
  }, [view, pendingCreds]);

  const handleProfileSelect = (type: ProfileType) => {
    setSelectedProfile(type);
    setView('REGISTER');
    setError(null);
    setSuccessMessage(null);

    setName('');
    setPassword('');
    setEmail('');
    setProfessionalCouncil('CRM');
    setProfessionalCode('');
    setCnpj('');
    setGuardianName('');
    setGuardianPin('');
    setChildUsername('');
    setChildPassword('');
  };

  const executeRegistration = async () => {
      setLoading(true);
      setError(null);

      // Re-sanitize inputs
      const cleanEmail = email.trim();
      const cleanPassword = password;
      const cleanGuardianPin = guardianPin.trim();
      const cleanChildUsername = childUsername.trim().toLowerCase().replace(/\s+/g, '');

      try {
        if (selectedProfile === ProfileType.CHILD) {
            // 1. Cria o Responsável (Este receberá o e-mail de verificação)
            const guardianCredential = await auth.createUserWithEmailAndPassword(cleanEmail, cleanGuardianPin);
            const guardianUser = guardianCredential.user;

            if (guardianUser) {
                await guardianUser.updateProfile({ displayName: guardianName.trim() });
                // ENVIA O E-MAIL DE VERIFICAÇÃO NATIVO DO FIREBASE
                await guardianUser.sendEmailVerification();
            }

            const guardianData = {
              uid: guardianUser?.uid,
              email: guardianUser?.email,
              displayName: guardianName.trim(),
              profileType: ProfileType.ADULT,
              manages: [],
              createdAt: Date.now(),
            };
            if (guardianUser) await db.collection("users").doc(guardianUser.uid).set(guardianData);

            // 2. Cria a Criança (Sem verificação de email pois é fake)
            const childFullEmail = `${cleanChildUsername}@child.eab.app`;
            // Pequeno delay para garantir ordem no backend se necessário
            await new Promise(r => setTimeout(r, 500));

            const childCredential = await auth.createUserWithEmailAndPassword(childFullEmail, childPassword);
            const childUser = childCredential.user;
            if (childUser) await childUser.updateProfile({ displayName: name.trim() });

            const childData = {
              uid: childUser?.uid,
              email: childFullEmail,
              displayName: name.trim(),
              childUsername: cleanChildUsername,
              profileType: ProfileType.CHILD,
              linkedGuardianId: guardianUser?.uid,
              childPassword: childPassword,
              createdAt: Date.now(),
            };
            if (childUser) await db.collection("users").doc(childUser.uid).set(childData);

            // 3. Vincula e prepara verificação
            // Logar como pai para verificação
            await auth.signInWithEmailAndPassword(cleanEmail, cleanGuardianPin);
            if (guardianUser) {
                await db.collection("users").doc(guardianUser.uid).update({
                    manages: firebase.firestore.FieldValue.arrayUnion(childUser?.uid),
                });
            }

            setPendingCreds({ email: cleanEmail, password: cleanGuardianPin });
            setView('VERIFY_EMAIL');

        } else {
            // Adulto, Profissional ou Escola
            const userCredential = await auth.createUserWithEmailAndPassword(cleanEmail, cleanPassword);
            const user = userCredential.user;

            if (user) {
                await user.updateProfile({ displayName: name.trim() });
                // ENVIA O E-MAIL DE VERIFICAÇÃO NATIVO DO FIREBASE
                await user.sendEmailVerification();
            }

            let profileTypeToSave = null; 
            if (selectedProfile === ProfileType.PROFESSIONAL) profileTypeToSave = ProfileType.PROFESSIONAL;
            if (selectedProfile === ProfileType.SCHOOL) profileTypeToSave = ProfileType.SCHOOL;

            const userData: any = {
              uid: user?.uid,
              email: user?.email,
              displayName: name.trim(),
              profileType: profileTypeToSave, 
              createdAt: Date.now(),
            };

            if (selectedProfile === ProfileType.PROFESSIONAL) {
                userData.professionalCouncil = professionalCouncil;
                userData.professionalCode = professionalCode;
                userData.professionalId = `${professionalCouncil} ${professionalCode}`;
            }

            if (selectedProfile === ProfileType.SCHOOL) {
                userData.cnpj = cnpj.replace(/[^\d]+/g, ''); 
            }

            if (user) await db.collection("users").doc(user.uid).set(userData);

            // Mantém logado para a tela de verificação
            setPendingCreds({ email: cleanEmail, password: cleanPassword });
            setView('VERIFY_EMAIL');
        }
      } catch (err: any) {
          console.error(err);
          let msg = "Erro ao criar conta.";
          if (err.code === 'auth/email-already-in-use') msg = "Este e-mail já está em uso.";
          if (err.code === 'auth/weak-password') msg = "A senha é muito fraca.";
          setError(msg);
      } finally {
          setLoading(false);
      }
  };

  const resendVerification = async () => {
      if (auth.currentUser) {
          try {
              await auth.currentUser.sendEmailVerification();
              setSuccessMessage("Novo e-mail de verificação enviado!");
          } catch (e) {
              setError("Aguarde alguns minutos antes de reenviar.");
          }
      }
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setSuccessMessage(null);

    const cleanEmail = email.trim(); 
    const cleanPassword = password; 
    const cleanGuardianPin = guardianPin.trim();
    const cleanChildUsername = childUsername.trim().toLowerCase().replace(/\s+/g, ''); 

    try {
      if (view === 'REGISTER') {
        if (!selectedProfile) throw new Error("Erro: Perfil não selecionado.");

        if (selectedProfile === ProfileType.CHILD) {
          if (!cleanEmail || !guardianName.trim() || !cleanGuardianPin)
            throw new Error("Preencha os dados do Responsável.");
          if (!name.trim() || !cleanChildUsername || !childPassword)
            throw new Error("Preencha os dados da Criança.");
          if (cleanGuardianPin.length < 6)
            throw new Error("A senha do responsável deve ter no mínimo 6 caracteres.");
          if (childPassword.length < 6)
            throw new Error("A senha da criança deve ter no mínimo 6 caracteres.");
          if (/[^a-z0-9._-]/.test(cleanChildUsername)) {
             throw new Error("O usuário da criança deve conter apenas letras minúsculas, números, ponto ou traço.");
          }
        } else {
          if (!name.trim() || !cleanEmail || !cleanPassword)
            throw new Error("Preencha todos os campos.");
          if (selectedProfile === ProfileType.PROFESSIONAL && !professionalCode) {
             throw new Error("Por favor, preencha o número de registro profissional.");
          }
          if (selectedProfile === ProfileType.SCHOOL && !cnpj) {
             throw new Error("Por favor, preencha o CNPJ da escola.");
          }
        }

        // INICIA O PROCESSO DE REGISTRO E VERIFICAÇÃO
        await executeRegistration();
        return;
      } 

      // --- LOGIN FLOW ---
      let loginIdentifier = cleanEmail;
      let isChildLogin = false;
      if (!loginIdentifier.includes('@')) {
        loginIdentifier = `${loginIdentifier.toLowerCase().replace(/\s+/g, '')}@child.eab.app`;
        isChildLogin = true;
      } else if (loginIdentifier.endsWith('@child.eab.app')) {
        isChildLogin = true;
      }

      const cred = await auth.signInWithEmailAndPassword(loginIdentifier, cleanPassword);

      // --- CHECK EMAIL VERIFICATION ---
      // Se não for criança (que tem email fake), EXIGE verificação
      if (cred.user && !cred.user.emailVerified && !isChildLogin) {
          setPendingCreds({ email: loginIdentifier, password: cleanPassword });
          setView('VERIFY_EMAIL');
      } else {
          onLoginSuccess();
      }

    } catch (err: any) {
      console.error(err);
      let msg = "Erro ao processar.";
      if (err.message) msg = err.message;
      if (err.code === 'auth/weak-password') msg = "A senha deve ter pelo menos 6 caracteres.";
      if (err.code === 'auth/invalid-email') msg = "O formato do e-mail é inválido.";
      if (err.code === 'auth/email-already-in-use') {
        if (view === 'REGISTER' && selectedProfile === ProfileType.CHILD && !guardianName)
          msg = "Este e-mail de responsável já está cadastrado.";
        else if (view === 'REGISTER' && selectedProfile === ProfileType.CHILD)
          msg = "Este nome de usuário para a criança já existe. Tente outro.";
        else msg = "Este e-mail já está cadastrado. Tente fazer login.";
      }
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' || err.code === 'auth/invalid-login-credentials') {
        msg = "Dados de acesso incorretos. Verifique e-mail/usuário e senha.";
      }
      setError(msg);
    } finally {
      if (view !== 'VERIFY_EMAIL') setLoading(false);
    }
  };

  const getThemeColor = () => {
      if (view === 'REGISTER' || view === 'VERIFY_EMAIL') {
          if (selectedProfile === ProfileType.CHILD) return pastel.blue;
          if (selectedProfile === ProfileType.PROFESSIONAL) return pastel.teal;
          if (selectedProfile === ProfileType.SCHOOL) return pastel.purple;
          return pastel.yellow;
      }
      return pastel.yellow;
  };

  // Se o estado showLanding for verdadeiro, renderiza a apresentação
  if (showLanding) {
      return <LandingPage onBack={() => setShowLanding(false)} onRegister={() => { setShowLanding(false); setView('PROFILE_SELECT'); }} />;
  }

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center p-4 font-sans"
      style={{
        background: `linear-gradient(135deg, ${pastel.blue} 0%, ${pastel.yellow} 25%, ${pastel.green} 60%, ${pastel.purple} 100%)`,
      }}
    >
      <div
        className="w-full max-w-2xl rounded-3xl p-6 shadow-3xl transition-all duration-300 hover:shadow-4xl bg-white/95 backdrop-blur-sm relative overflow-hidden border-[6px] border-slate-100"
        style={{
          boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.4)',
          borderColor: getThemeColor(),
        }}
      >
        <div className="flex flex-col items-center mb-6">
          <div className="transform scale-75 mb-[-10px]">
            <RobotMascot mood={MoodType.HAPPY} />
          </div>
          <h1 className="text-3xl font-black tracking-wide mb-1 text-slate-900" style={{ color: pastel.blue }}>EAB</h1>
          <p className="text-slate-800 font-medium text-center text-sm">
            {view === 'PROFILE_SELECT' ? 'Quem vai usar o aplicativo?' : view === 'VERIFY_EMAIL' ? 'Confirmação de E-mail' : 'Bem-vindo(a), vamos começar o dia!'}
          </p>
        </div>

        {successMessage && (
          <div className="mb-4 text-center text-sm p-3 rounded-xl border-2 animate-in fade-in slide-in-from-top-1 shadow-lg flex items-center justify-center gap-2" style={{ color: '#155724', backgroundColor: '#D4EDDA', borderColor: '#C3E6CB' }}>
            <CheckCircle2 size={16} /> <span className="font-bold">{successMessage}</span>
          </div>
        )}

        {error && (
          <div className="mb-4 text-center text-sm bg-red-100 p-3 rounded-xl border-2 animate-in fade-in slide-in-from-top-1 shadow-lg" style={{ color: '#C0392B', borderColor: pastel.pink }}>
            {error}
          </div>
        )}

        {/* PROFILE SELECT */}
        {view === 'PROFILE_SELECT' && (
          <div className="space-y-6 animate-in slide-in-from-right-4 duration-300 w-full">
            <fieldset className="rounded-3xl p-6 pt-4 relative border-4 shadow-xl bg-white/50 backdrop-blur-sm" style={{ border: `3px solid ${pastel.blue}` }}>
