interface LandingPageProps {
    onBack: () => void;
    onRegister: () => void;
}

const LandingPage: React.FC<LandingPageProps> = ({ onBack, onRegister }) => {
    const [scale, setScale] = useState(1);

    // Ajusta o zoom da página APENAS para visualização no navegador (não afeta o PDF)
    useEffect(() => {
        const handleResize = () => {
            const margin = 20; 
            const a4Width = 794; 
            const availableWidth = window.innerWidth - margin;
            const newScale = availableWidth < a4Width ? availableWidth / a4Width : 1;
            setScale(newScale);
        };

        handleResize();
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const handleDownloadPDF = () => {
        const element = document.getElementById('print-container');
        if (!element) return;

        const btn = document.getElementById('btn-download');
        if(btn) btn.innerText = "Preparando Arquivo...";

        const opt = {
            margin:       0,
            filename:     'EAB_Apresentacao_Projeto_2026.pdf',
            image:        { type: 'jpeg', quality: 1.0 },
            html2canvas:  { 
                scale: 3, // Alta fidelidade
                useCORS: true, 
                letterRendering: true,
                scrollY: 0,
                windowWidth: 794,
                logging: false,
                backgroundColor: '#F1F5F9'
            },
            jsPDF:        { unit: 'px', format: 'a4', orientation: 'portrait', hotfixes: ['px_scaling'] },
            pagebreak:    { mode: 'css', after: '.a4-page' }
        };

        // @ts-ignore
        if (window.html2pdf) {
