        const handleResize = () => {
            const margin = 40; 
            const a4Width = 794; 
            const availableWidth = window.innerWidth - margin;
            const newScale = availableWidth < a4Width ? availableWidth / a4Width : 1;
            setScale(newScale);
        };

        handleResize();
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const handleDownloadPDF = async () => {
        const element = document.getElementById('print-container');
        if (!element) return;

        const btn = document.getElementById('btn-download');
        const originalBtnContent = btn ? btn.innerHTML : '';

        if(btn) {
            btn.innerHTML = '<span class="flex items-center gap-2"><svg class="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle><path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg> Processando...</span>';
        }

        try {
            // 1. CLONAGEM: Isolar o conteúdo de qualquer transform CSS da tela
            const clone = element.cloneNode(true) as HTMLElement;

            // Remover sombras, margens e CONFIGURAR QUEBRAS DE PÁGINA MANUALMENTE
            const pages = clone.querySelectorAll('.a4-page');
            pages.forEach((page: any, index) => {
                page.style.boxShadow = 'none';
                page.style.margin = '0';
                page.style.marginBottom = '0';
                // Remove bordas arredondadas ou qualquer estilo de tela
                page.style.borderRadius = '0';

                // CRÍTICO: Adiciona quebra APENAS se não for a última página
                if (index < pages.length - 1) {
                    page.style.pageBreakAfter = 'always';
                } else {
                    page.style.pageBreakAfter = 'auto'; // Evita página em branco no final
                }
            });

            // 2. CONTAINER INVISÍVEL: Renderizar fora da viewport com largura fixa exata
            const container = document.createElement('div');
            container.style.position = 'fixed';
            container.style.top = '-10000px';
            container.style.left = '0';
            container.style.width = '794px'; // Largura A4 padrão em 96dpi
            container.style.margin = '0';
            container.style.padding = '0';
            container.style.zIndex = '-9999';
            container.appendChild(clone);
            document.body.appendChild(container);

            // 3. CONFIGURAÇÃO DO HTML2PDF
            const opt = {
                margin:       0,
                filename:     'EAB_Documentacao_Master_2026.pdf',
                image:        { type: 'jpeg', quality: 0.98 },
                html2canvas:  { 
                    scale: 2, // Melhor resolução
                    useCORS: true, 
                    letterRendering: true,
                    scrollY: 0,
                    width: 794,
                    windowWidth: 794, 
                    logging: false,
                    backgroundColor: '#ffffff'
                },
                jsPDF: { 
                    unit: 'px', 
                    format: [794, 1122], // Altura exata
                    orientation: 'portrait',
                    compress: true
                },
                // Removemos 'after' automático para evitar a última página em branco
                // A quebra agora é controlada pelo loop forEach acima
                pagebreak: { mode: ['css', 'legacy'] } 
            };

            // @ts-ignore
            if (window.html2pdf) {
                // @ts-ignore
                await window.html2pdf().set(opt).from(clone).save();
            }

            // Limpeza
            document.body.removeChild(container);

        } catch (err) {
            console.error("PDF Error:", err);
            alert("Erro ao gerar PDF. Tente novamente.");
        } finally {
            if(btn) btn.innerHTML = originalBtnContent;
        }
    };

    // Altura total visual para o scroll da tela (não afeta o PDF)
    const VISUAL_CONTENT_HEIGHT = 10 * (1122 + 50); 

