                // Usamos apenas CSS para respeitar o 'page-break-after' que injetamos
                pagebreak: { mode: ['css'] } 
            };

            // @ts-ignore
            if (window.html2pdf) {
                // @ts-ignore
                await window.html2pdf().set(opt).from(clone).save();
            }

            // Limpeza
            document.body.removeChild(container);

