                    <div className="w-10 h-10 bg-white rounded-2xl flex items-center justify-center text-xl shadow-inner border border-slate-200">🤖</div>
                    <div className="leading-tight">
                        <span className="font-black text-lg block uppercase tracking-tighter text-blue-400">EAB MASTER 2026</span>
                        <span className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Documentação Técnica v2.5</span>
