                image: { type: 'jpeg', quality: 0.98 },
                html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, width: 794, windowWidth: 794, logging: false, backgroundColor: '#ffffff' },
                jsPDF: { unit: 'px', format: [794, 1123], orientation: 'portrait', compress: true },
                pagebreak: { mode: ['css'] } 
            };

            // @ts-ignore
            if (window.html2pdf) {
                // @ts-ignore
                await window.html2pdf().set(opt).from(clone).save();
            }
            document.body.removeChild(container);
        } catch (err) {
            console.error("PDF Error:", err);
        } finally {
            if(btn) btn.innerHTML = originalBtnContent;
        }
    };

